def test_use_cm():
    # verify that the `use_cm` attribute is implemented.
    if not np:
        skip("numpy not installed.")

    u, x, y, z = symbols("u, x:z")

    s = List2DSeries([1, 2, 3, 4], [5, 6, 7, 8], use_cm=True)
